"""
mkt-original commentary -- Jeremiah chapters 46-48
Run: python3 scripts/zc-original-jeremiah-46-48.py

Oracles Against the Nations (OAN) — Part 1 of 2:
  Ch46: Oracle against Egypt — Carchemish (609 BCE) and general Egyptian humiliation;
    ends with comfort for Jacob (vv27-28 = 30:10-11 double).
  Ch47: Oracle against Philistia — northern flood imagery; sword lament.
  Ch48: Oracle against Moab — most extensive OAN in Jeremiah (47 vv); pride-judgment
    theme, Chemosh idol-shame, dregs/wine-jar metaphors; ends with eschatological
    restoration (v47).
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(layer, book):
    p = ROOT / "data" / "commentary" / f"mkt-{layer}" / f"{book}.json"
    return json.loads(p.read_text()) if p.exists() else {}

def save_comm(layer, book, data):
    p = ROOT / "data" / "commentary" / f"mkt-{layer}" / f"{book}.json"
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f"  wrote {p.relative_to(ROOT)}")

def merge_comm(existing, new_data):
    # Never overwrite existing entries — safe to re-run
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

JEREMIAH = {
  "46": {
    "1": "<p><strong>ʾĂšer hāyâ dĕḇar-YHWH ʾel-Yirmĕyāhû hannāḇîʾ ʿal-haggôyim</strong> (<em>ʾal-haggôyim</em>): the superscription to the entire Oracles Against the Nations (OAN) collection (chs 46-51). The phrase <em>ʿal-haggôyim</em> (concerning the nations) positions these oracles as YHWH's sovereign word over powers beyond Israel — a universal claim of divine governance. Comparable OAN collections appear in Isaiah (13-23), Ezekiel (25-32), and Amos (1-2). The OAN genre is not mere political commentary but theo-political declaration: YHWH's <em>mišpāṭ</em> (judgment) extends to all nations, not only to Israel.</p>",
    "2": "<p><strong>Lĕmiṣrāyim ʿal-ḥêl parʿōh Nĕḵô</strong> (<em>Lĕmiṣrāyim ʿal-ḥêl parʿōh Nĕḵô</em>): the historical anchor is precise — Pharaoh Neco II of Egypt met Nebuchadrezzar at Carchemish on the Euphrates in 605 BCE (the 4th year of Jehoiakim). Carchemish was the decisive battle that ended Egyptian hegemony over Canaan and established Babylonian supremacy. Jeremiah and Baruch were in Jerusalem during this battle (cf. ch36, where Jeremiah dictated the scroll in that same 4th year). The oracle thus interprets a contemporary geopolitical event through the lens of YHWH's sovereignty: Egypt's defeat at Carchemish was not merely Babylonian military superiority but YHWH's sentence on Egypt.</p>",
    "3": "<p><strong>ʿIrĕkû māgēn ûṣinnâ ûgišû lammilḥāmâ</strong> (<em>ʿIrĕkû māgēn ûṣinnâ</em>): the imperatives are sardonic — the prophet issues the war-marshal's call to Egypt's army. <em>māgēn</em> (small round shield, for hand-to-hand combat) and <em>ṣinnâ</em> (large full-body shield, for archers and spear-bearers) represent the two main infantry shield types. The mock-military exhortation sets up the reversal of vv5-6: the very troops being rallied will flee in terror. This dramatic irony is a characteristic feature of OAN rhetoric.</p>",
    "4": "<p><strong>ʾIsrû hassûsîm wĕʿălû happārāšîm wĕhityaṣṣĕḇû bĕḵôḇāʿîm</strong> (<em>ʾIsrû hassûsîm</em>): four imperatives continue the mock-rallying: harness the horses, mount the cavalry, stand in the helmets (<em>kôḇaʿ</em>), polish the spears (<em>mĕraqqu hammĕrāmāḥîm</em>, Piel of <em>rāqaʿ</em> — to beat thin, polish), and put on the coats of armor (<em>liḇšû hassirĕyōnōt</em>). The attention to military detail (shields, helmets, spears, armor) mimics the war-preparation genre found in Egyptian and Assyrian royal inscriptions. The full battle-array described in vv3-4 will be utterly routed in v5.</p>",
    "5": "<p><strong>Maddûaʿ rāʾîtî hēmmâ ḥattîm nĕsôgîm ʾāḥôr</strong> (<em>Maddûaʿ rāʾîtî hēmmâ ḥattîm nĕsôgîm ʾāḥôr</em>): the rhetorical question captures the prophet's mock-astonishment at the reversal — just summoned to battle, Egypt's warriors are already (<em>ḥattîm</em>, struck down, from <em>ḥātat</em>, to be shattered/dismayed) and fleeing backward (<em>nĕsôgîm ʾāḥôr</em>). <strong>Mĕḡubbĕrêhem mukkaʾtîm ûmānôs nāsû wĕlōʾ hifnû</strong> (<em>mĕḡubbĕrêhem mukkaʾtîm</em>): their warriors are beaten down; they flee without looking back. <strong>Māgôr missāḇîḇ</strong> (<em>Māgôr missāḇîḇ</em>): \"terror on every side\" — Jeremiah's signature phrase (6:25; 20:3-4, 10; 49:29), which he applied to Judah and which his enemy Pashhur received as a personal name (20:3). Here YHWH extends the same terror-oracle to Egypt.</p>",
    "6": "<p><strong>ʾAl-yānûs haqal wĕʾal-yimmāleṭ haggibbôr</strong> (<em>ʾAl-yānûs haqal wĕʾal-yimmāleṭ haggibbôr</em>): the swift (<em>qal</em>) cannot flee and the mighty (<em>gibbôr</em>) cannot escape — the two human strategies of survival (speed and strength) are both nullified. <strong>Ṣāpônâ ʿal-yad nĕhar-pĕrāt kāšĕlû wĕnāpālû</strong> (<em>ṣāpônâ ʿal-yad nĕhar-pĕrāt kāšĕlû wĕnāpālû</em>): they stumble and fall beside the Euphrates — the very river that defined Egypt's northern ambition. Carchemish was intended to be Egypt's eastward expansion; it became her burial ground.</p>",
    "7": "<p><strong>Mî-zeh kayyĕʾōr yaʿăleh kayyĕʾōrîm yitgāʾăšû mêmāyw</strong> (<em>Mî-zeh kayyĕʾōr yaʿăleh</em>): the rhetorical question opens the second movement (vv7-12) with a description of Egypt as the Nile in flood. <em>yĕʾōr</em> is the Egyptian loanword for the Nile (used throughout Exod 7-8 for the Nile's waters); <em>yitgāʾăšû</em> (Hitpael of <em>gāʾaš</em>, to surge, rush) pictures the inundation waters in turbulent surge. The Nile's annual flood was the source of Egypt's agricultural life — Jeremiah uses it ironically: Egypt's rise against the nations is like the Nile flood, impressive but ultimately receding.</p>",
    "8": "<p><strong>Miṣrāyim kayyĕʾōr yaʿăleh ûkayyĕʾōrîm yitgāʾăšû māyim</strong> (<em>Miṣrāyim kayyĕʾōr yaʿăleh</em>): Egypt's self-declaration is quoted: <em>ʾaʿăleh ʾăkassel ʾāreṣ ʾôḇîdâ ʿîr wĕyōšĕḇê ḇāh</em> — \"I will rise, I will cover the earth; I will destroy city and inhabitants.\" The triple first-person imperfect (I will rise, I will cover, I will destroy) mimics the divine speech pattern of conquest (cf. Isa 14:13-14, where the king of Babylon uses <em>ʾeʿĕleh / ʾāśîm / ʾĕdammeh</em> in hubristic self-declaration). Egypt's pride matches Babylon's and receives the same judgment.</p>",
    "9": "<p><strong>ʿĂlû hassûsîm wĕhitĕhôlĕlû hāreḵeḇ wĕyēṣĕʾû haggibbôrîm</strong> (<em>ʿĂlû hassûsîm</em>): the mock-rally continues with the international composition of Egypt's forces. <strong>Kûš ûFût tōpĕśê māgēn ûlûdîm tōpĕśê dōrĕḵê qāšet</strong> (<em>Kûš ûFût ûlûdîm</em>): Cush (Upper Nubia/Ethiopia), Put (Libya), and Lud (Lydia or North Africa — debated; cf. Ezek 27:10; 30:5). All three were mercenary forces in Egypt's army. The enumeration of Egypt's multinational mercenary forces is both impressive and ironic — their very diversity signals Egypt's dependence on hired power rather than the divine patron who alone can save.</p>",
    "10": "<p><strong>Ûhayyôm hahûʾ laʾădōnāy YHWH ṣĕḇāʾôt yôm nāqām lĕhinnaqqēm mîṣṣārāyw</strong> (<em>Ûhayyôm hahûʾ laʾădōnāy YHWH ṣĕḇāʾôt</em>): the theological summit of the oracle — Carchemish is redefined as <em>yôm nāqām</em> (day of vengeance/retribution). YHWH as the avenger (<em>nāqam</em>) exercises his justice on his enemies through the Babylonian instrument. <strong>Wĕʾāḵĕlâ ḥereḇ wĕśāḇĕʿâ wĕrāwĕtâ middāmām</strong> (<em>wĕʾāḵĕlâ ḥereḇ wĕśāḇĕʿâ wĕrāwĕtâ middāmām</em>): the sword personified — eating (<em>ʾāḵal</em>), satisfied (<em>śāḇēaʿ</em>), and drinking its fill of blood (<em>rāwâ</em>) — is the combat-violence imagery also used in Isa 34:5-7 and Ezek 21. <strong>Kî zeḇaḥ laʾădōnāy YHWH ṣĕḇāʾôt bĕʾereṣ ṣāpôn ʿal-nĕhar-pĕrāt</strong> (<em>kî zeḇaḥ laʾădōnāy YHWH ṣĕḇāʾôt</em>): the battle is a <em>zeḇaḥ</em> (sacrificial feast) — YHWH as divine warrior hosting a sacrifice whose victims are Egypt's army. The same image appears in Isa 34:6 (YHWH's sword has a sacrifice in Bozrah) and Ezek 39:17-20 (the feast of YHWH's sacrifice).</p>",
    "11": "<p><strong>ʿĂlî gilʿād ûqĕḥî ṣŏrî bĕtûlat bat-miṣrāyim</strong> (<em>ʾĂlî gilʿād ûqĕḥî ṣŏrî</em>): the command to \"go up to Gilead and take balm\" is mocking — Gilead's famous healing balsam (<em>ṣŏrî</em>, resin/balm; cf. 8:22; 51:8; Gen 37:25) cannot help Egypt. <strong>Lāšāwĕʾ hirbbêt rĕpūʾôt tĕʿālâ ʾên lāḵ</strong> (<em>Lāšāwĕʾ hirbbêt rĕpūʾôt tĕʿālâ ʾên lāḵ</em>): \"in vain you heap up medicines; there is no healing for you.\" The phrase <em>tĕʿālâ ʾên lāḵ</em> (no healing/restoration for you) was used for Jerusalem in 8:22 and for Babylon in 51:8 — the same incurability that characterized unfaithful Zion now belongs to Egypt. The wound of military defeat is beyond pharmaceutical remedy because it is YHWH's judgment.</p>",
    "12": "<p><strong>Šāmĕʿû gôyim qĕlônēḵ ûṣiwwāḥătēḵ māĺĕʾâ hāʾāreṣ</strong> (<em>Šāmĕʿû gôyim qĕlônēḵ</em>): the nations have heard Egypt's shame (<em>qālôn</em>). <strong>Kî-gibbôr bĕgibbôr kāšāl gam-šĕnêhem yaḥdāw nāpālû</strong> (<em>Kî-gibbôr bĕgibbôr kāšāl</em>): the collapse is total — warrior stumbled over warrior, and together they fell. The image of crowded, chaotic retreat captures the scene at Carchemish: the disciplined formation of an advancing army becomes a tumbling mass of fleeing men. International shame — the nations heard the noise of the collapse — is the polar opposite of the military glory Egypt projected in vv7-9.</p>",
    "13": "<p><strong>Haddāḇār ʾăšer-dibber YHWH ʾel-Yirmĕyāhû hannāḇîʾ lāḇôʾ Nĕḇûḵadrĕʾṣṣar melek-bāḇel lĕhakkôt ʾet-ʾereṣ miṣrāyim</strong> (<em>lāḇôʾ Nĕḇûḵadrĕʾṣṣar... lĕhakkôt ʾet-ʾereṣ miṣrāyim</em>): a second oracle heading (vv13-26) introduces the announcement of Nebuchadnezzar's future invasion of Egypt itself (this likely refers to 568/567 BCE, when Nebuchadnezzar did campaign in Egypt). The oracle extends beyond Carchemish to the comprehensive humiliation of Egypt on its own soil.</p>",
    "14": "<p><strong>Haggîdû bĕmiṣrāyim wĕhašmîʿû bĕmigdōl ûhašmîʿû bĕnōp ûḇĕtaḥpanḥēs</strong> (<em>bĕmigdōl ûḇĕnōp ûḇĕtaḥpanḥēs</em>): the three locations — Migdol (NE border fortress), Noph/Memphis (capital of Lower Egypt), Tahpanhes (NE Delta fortress where Jeremiah was taken, ch43) — represent Egypt's northern defense system. <strong>ʾEmōr hiṯyaṣṣēḇ wahāḵēn lāḵ kî ʾāḵĕlâ ḥereḇ sĕḇîḇāyiḵ</strong> (<em>kî ʾāḵĕlâ ḥereḇ sĕḇîḇāyiḵ</em>): \"the sword is eating all around you\" — the devouring sword of v10 now reaches Egypt's own garrisons.</p>",
    "15": "<p><strong>Maddûaʿ nusḥap ʾabbîrêḵ lōʾ ʿāmad kî YHWH hǝdāpô</strong> (<em>YHWH hǝdāpô</em>): \"Why were your warriors swept away? They could not stand, because YHWH thrust them down.\" The <em>hāḏap</em> (to thrust, push down) attributes Egypt's military collapse directly to YHWH's action. Egypt's <em>ʾabbîrîm</em> (mighty ones, strong ones — used of horses in 8:16; Ps 22:13) are not felled by superior human arms but by the divine <em>dāhap</em>. The passive helplessness of Egypt before the divine push echoes the exodus reversal: Egypt's horses and riders were once the greatest military power; YHWH dispersed them then, and he does so again now.</p>",
    "16": "<p><strong>Hirbâ kôšēl gam-nāpal ʾîš ʾel-rēʿēhû wayyōmĕrû qûmâ wĕnāšûḇâ ʾel-ʿammēnû wĕʾel-ʾereṣ môlādtēnû</strong> (<em>ʾel-ʿammēnû wĕʾel-ʾereṣ môlādtēnû</em>): the mercenaries — Cush, Put, and Lud of v9 — abandon Egypt, calling to one another to return to their homelands. <strong>Mippĕnê ḥereḇ hayyônâ</strong> (<em>mippĕnê ḥereḇ hayyônâ</em>): \"away from the oppressing/crushing sword\" — <em>yônâ</em> (Qal participle of <em>yānâ</em>, to oppress, crush) describes the sword as an oppressive force. The irony: Egypt who oppressed others is now the one causing flight by her own oppressive judgment-sword.</p>",
    "17": "<p><strong>Qārĕʾû šām parʿōh melek-miṣrāyim šāʾôn heʿĕḇîr hammôʿēd</strong> (<em>šāʾôn heʿĕḇîr hammôʿēd</em>): the mocking epithet for Pharaoh — <em>šāʾôn</em> (noise, clamor) and <em>heʿĕḇîr hammôʿēd</em> (he let the appointed time/opportunity pass). The phrase creates a new throne-name for Pharaoh: \"King of Egypt: Nothing but Noise who Missed his Moment.\" The <em>mōʿēd</em> (appointed time, opportunity) refers to the moment at which Egypt could have acted decisively — instead his vaunted military power was only noise. Isaiah 36:6 uses a similar demotion-image for Egypt as a broken reed.</p>",
    "18": "<p><strong>Ḥay-ʾānî nĕʾum-hammelek YHWH ṣĕḇāʾôt šĕmô kî kĕṯāḇôr bāhārîm yāḇôʾ ûḵḵarmel bayyām yāḇôʾ</strong> (<em>kî kĕṯāḇôr bāhārîm... ûḵḵarmel bayyām</em>): the divine oath formula (<em>ḥay-ʾānî</em>, \"as I live\") introduces the certainty of the invasion. Tabor (the conspicuous mountain of the Jezreel valley) and Carmel (the promontory jutting into the Mediterranean) — two of the most visually prominent landmarks in Canaan — serve as similes for Nebuchadnezzar's inevitable, unmistakable coming against Egypt. <em>YHWH ṣĕḇāʾôt šĕmô</em> (\"the LORD of hosts is his name\") is the divine-warrior name formula that authenticates the oath.</p>",
    "19": "<p><strong>Kĕlê gōlâ ʿăśî lāḵ yōšeḇet bat-miṣrāyim</strong> (<em>Kĕlê gōlâ ʿăśî lāḵ</em>): \"Pack your bags for exile\" — <em>kĕlê gōlâ</em> (exile-vessels, the gear of a deportee) is the same image used in Ezek 12:3-7 for Ezekiel's enacted prophecy of exile. Egypt's inhabitants must prepare for the same deportation she inflicted on others. <strong>Kî-nōp lĕšammâ tihyeh wĕnisrĕpâ mēʾên yôšēḇ</strong> (<em>Kî-nōp lĕšammâ tihyeh</em>): Memphis (<em>nōp</em>) will become desolation (<em>šammâ</em>) without inhabitant — the very vocabulary of judgment pronounced on Jerusalem (4:7; 9:11; 10:22; 25:11) is applied to Egypt's capital. The empire is no safer than the covenant city when YHWH judges.</p>",
    "20": "<p><strong>ʿEglâ yĕpēh-piyyâ miṣrāyim</strong> (<em>ʿEglâ yĕpēh-piyyâ miṣrāyim</em>): \"Egypt is a beautiful heifer\" — the calf/heifer metaphor plays on multiple registers: Egypt's abundance (like a well-fed heifer), her fertility (the Nile-blessed land), and her vulnerability (an unsuspecting animal about to be slaughtered). <strong>Qereṣ mîṣṣāpôn bāʾ bāʾ</strong> (<em>Qereṣ mîṣṣāpôn bāʾ bāʾ</em>): \"a horsefly/gadfly from the north has come, it has come\" — the doubled <em>bāʾ</em> emphasizes the arrival's certainty. <em>Qereṣ</em> (horsefly, gadfly; only here in the OT) uses a startling bathos: the greatest empire of the age is undone not by a superior empire but by an insect (<em>Nebuchadnezzar as horsefly</em>). The same reductive irony appears in Isa 7:18 (YHWH whistling for flies from Egypt and bees from Assyria).</p>",
    "21": "<p><strong>Gam-śĕḵîrêhā bĕqirbāh kĕʿeglê marbeq</strong> (<em>Gam-śĕḵîrêhā bĕqirbāh kĕʿeglê marbeq</em>): the mercenaries within Egypt are \"like fattened calves\" (<em>ʿeglê marbeq</em> — stall-fed cattle, Amos 6:4; Mal 4:2) — well-fed, comfortable, and useless for real defense. <strong>Kî-gam-hēmmâ pānû nāsû yaḥdāw lōʾ ʿāmādû kî yôm ʾêdām bāʾ ʿălêhem ʿēt pĕquddātām</strong> (<em>kî yôm ʾêdām bāʾ ʿălêhem ʿēt pĕquddātām</em>): \"for the day of their calamity has come upon them, the time of their reckoning\" — <em>ʿēt pĕquddâ</em> (time of visitation/reckoning) is YHWH's appointed moment of judgment, the same vocabulary used for Israel's exile (10:15; 11:23; 23:12; 50:27).</p>",
    "22": "<p><strong>Qôlāh kaṇṇāḥāš yēlēḵ kî-ḇaḥayil yēlēḵû</strong> (<em>Qôlāh kaṇṇāḥāš yēlēḵ</em>): \"her sound is like a hissing serpent as they advance\" — a double image: Egypt retreating sounds like a hissing snake (the serpent symbolism is rich, as Egypt's royal symbol was the uraeus serpent <em>nāḥāš</em>); simultaneously the invaders advance like woodcutters with axes (<em>bĕqarddummôt</em>). The serpent-sound in retreat is a devastating reversal of the royal uraeus symbol of power. <strong>Wayyāḇōʾû lāh bĕqarddummôt kĕḥōṭĕḇê ʿēṣîm</strong> (<em>kĕḥōṭĕḇê ʿēṣîm</em>): the attackers are woodcutters — Egypt's army is treated as a mere forest to be logged.</p>",
    "23": "<p><strong>Kārĕtû yĕʿārāh nĕʾum-YHWH kî lōʾ yiḥqēr kî rābû mēʾarbeh wĕʾên lāhem mispar</strong> (<em>kî rābû mēʾarbeh wĕʾên lāhem mispar</em>): they cut down her forest — \"though it is dense\" (<em>kî lōʾ yiḥqēr</em>, for it cannot be explored/fathomed) — because Babylon's army is more numerous than locusts (<em>mēʾarbeh</em>) and without number (<em>wĕʾên lāhem mispar</em>). The locust simile for a conquering army is a common ANE combat image (Joel 1-2; Judg 6:5; 7:12). Egypt's impenetrable forests offer no shelter because the attacking force is numerically overwhelming.</p>",
    "24": "<p><strong>Hōḇîšâ bat-miṣrāyim nittĕnâ bĕyad ʿam ṣāpôn</strong> (<em>Hōḇîšâ bat-miṣrāyim nittĕnâ bĕyad ʿam ṣāpôn</em>): \"the daughter of Egypt is shamed; she is handed over to a people from the north.\" The feminine personification (<em>bat-miṣrāyim</em>, daughter of Egypt) is the standard OAN form for the nation as a woman suffering defeat and shame (<em>bōšet</em>). The passive <em>nittĕnâ</em> (she is handed over, Niphal perfect) credits YHWH as the agent: Egypt is not merely conquered; she is given by YHWH into Babylon's hands.</p>",
    "25": "<p><strong>ʾĀmar YHWH ṣĕḇāʾôt ʾĕlōhê yiśrāʾēl hinnĕnî pōqēd ʾel-ʾāmôn minnōʾ wĕʿal-parʿōh wĕʿal-miṣrāyim wĕʿal-ʾĕlōhêhā wĕʿal-mĕlāḵêhā</strong> (<em>hinnĕnî pōqēd ʾel-ʾāmôn minnōʾ</em>): Amon of No — the chief deity of Thebes (Upper Egypt; <em>nōʾ</em> = Thebes, Ezek 30:14-15; Nah 3:8), whose full name was Amon-Ra. YHWH's judgment explicitly targets the divine patron of Egypt: <em>wĕʿal-ʾĕlōhêhā</em> (and her gods). The oracle is not merely political but theological: YHWH asserts his sovereignty over Egypt's divine pantheon. Cf. Exod 12:12: \"against all the gods of Egypt I will execute judgments\" — the exodus pattern is being recapitulated.</p>",
    "26": "<p><strong>Ûnĕtattîm bĕyad mĕḇaqšê napšām ûḇĕyad Nĕḇûḵadrĕʾṣṣar melek-bāḇel ûḇĕyad-ʿăḇādāyw</strong> (<em>ûḇĕyad mĕḇaqšê napšām</em>): YHWH delivers them into the hands of \"those who seek their lives\" (<em>mĕḇaqšê napšām</em>) — the same phrase used for those who sought Jeremiah's life (11:21; 44:30). <strong>Wĕʾaḥărê-ḵēn tiššāḵēn kîmê-qedem nĕʾum-YHWH</strong> (<em>Wĕʾaḥărê-ḵēn tiššāḵēn kîmê-qedem</em>): \"But afterward Egypt will be inhabited again as in the days of old.\" This restoration footnote (like Moab's in 48:47 and Ammon's in 49:6) prevents the OAN from reading as pure annihilation — YHWH's judgment is not the last word even for the nations. Ezekiel 29:13-14 provides a parallel: Egypt will be restored, though to a lower status.</p>",
    "27": "<p><strong>Wĕʾattâ ʾal-tîrāʾ ʿaḇdî yaʿăqōḇ wĕʾal-tēḥat yiśrāʾēl</strong> (<em>Wĕʾattâ ʾal-tîrāʾ ʿaḇdî yaʿăqōḇ</em>): the oracle concludes with a remarkable turn to Jacob/Israel — vv27-28 are nearly identical to 30:10-11. After the oracle of doom against Egypt, the word to Israel is <em>ʾal-tîrāʾ</em> (do not fear) — YHWH's universal sovereignty over Egypt is precisely the ground of Israel's security. <strong>Kî hinnĕnî môšîʿăḵā mērāḥôq wĕʾet-zarʿăḵā mēʾereṣ šiḇyām</strong> (<em>hinnĕnî môšîʿăḵā mērāḥôq</em>): \"I am going to save you from far away and your descendants from the land of their captivity\" — the same YHWH who controls Nebuchadnezzar over Egypt is simultaneously the one who saves Jacob from exile. <strong>Wĕšāḇ yaʿăqōḇ wĕšāqaṭ wĕšaʿănan wĕʾên maḥărîd</strong> (<em>wĕšāḇ... wĕšāqaṭ wĕšaʿănan</em>): Jacob will return and be quiet (<em>šāqaṭ</em>), secure (<em>šaʿănan</em>), with no one causing trembling (<em>maḥărîd</em>, Hiphil participle of <em>ḥārad</em>) — a sequence of three šin-rooted words that pile up the completeness of restoration rest.</p>",
    "28": "<p><strong>ʾAttâ ʾal-tîrāʾ ʿaḇdî yaʿăqōḇ nĕʾum-YHWH kî ʾittĕḵā ʾānî</strong> (<em>kî ʾittĕḵā ʾānî</em>): \"for I am with you\" — the divine presence formula (<em>ʿimmānû</em> / <em>ʾittĕḵā</em>) that recurs throughout the call narrative (1:8, 19) and the letters to the exiles (29:14) is the ultimate assurance. <strong>Kî ʾeʿĕśeh kālâ bĕḵol-haggôyim ʾăšer hiddaḥtîḵā šāmmâ wĕʾōtĕḵā lōʾ-ʾeʿĕśeh ḵālâ ûyissartîḵā lammišpāṭ wĕnaqqēh lōʾ ʾănaqkeḵā</strong> (<em>kî ʾeʿĕśeh kālâ bĕḵol-haggôyim</em>): \"for I will make a complete end of all the nations to which I have driven you, but of you I will not make a complete end\" — the word <em>kālâ</em> (complete end, annihilation) is applied to the nations but denied for Jacob. <em>ûyissartîḵā lammišpāṭ wĕnaqqēh lōʾ ʾănaqkeḵā</em>: \"I will discipline you justly but will not leave you entirely unpunished\" — the tension of grace and justice: YHWH will not pretend the sin did not happen (<em>naqqēh lōʾ</em>, will not leave entirely unpunished) but will not destroy Jacob either. The difference between Israel and the nations is not Israel's merit but YHWH's covenant commitment to Jacob.</p>"
  },
  "47": {
    "1": "<p><strong>ʾĂšer hāyâ dĕḇar-YHWH ʾel-Yirmĕyāhû hannāḇîʾ ʾel-Pĕlištîm bĕṭerem yakkeh parʿōh ʾet-ʿazzâ</strong> (<em>bĕṭerem yakkeh parʿōh ʾet-ʿazzâ</em>): the oracle heading dates the Philistine oracle \"before Pharaoh attacked Gaza.\" This refers to Neco II's northward campaign in 609 BCE (when he also killed Josiah at Megiddo, 2 Kings 23:29) or a subsequent Egyptian incursion. The dating places the oracle before the event it partially describes — prophetic foreknowledge of Egyptian military action in Philistia. The Philistines occupied the SW coastal plain of Canaan (the five cities: Gaza, Ashkelon, Ashdod, Ekron, Gath).</p>",
    "2": "<p><strong>Kōh ʾāmar YHWH hinnēh mayim ʿōlîm mîṣṣāpôn wĕhāyû lĕnaḥal šôṭēp</strong> (<em>hinnēh mayim ʿōlîm mîṣṣāpôn wĕhāyû lĕnaḥal šôṭēp</em>): the flood imagery — waters rising from the north becoming an overflowing torrent (<em>naḥal šôṭēp</em>, lit. overflowing wadi) — appears also in Isa 8:7-8 for the Assyrian flood-invasion and in Jer 46:7-8 for the Egyptian Nile-flood. Here it applies to Babylon (\"from the north\") overwhelming Philistia. <strong>Wĕšāṭĕpû ʾereṣ ûmĕlōʾāh ʿîr wĕyōšĕḇê ḇāh</strong> (<em>Wĕšāṭĕpû ʾereṣ ûmĕlōʾāh</em>): they will swamp the land and its fullness — <em>wĕšāṭap</em> (to overflow, flood) applied to military invasion creates the same metaphorical totality: nothing remains dry, nothing escapes the flood of judgment.</p>",
    "3": "<p><strong>Miqqôl šaʿăṭat pārsôt ʾabbîrāyw mirrāʿaš lĕmerkĕḇōtāyw hāmôn galgillāyw</strong> (<em>miqqôl šaʿăṭat pārsôt ʾabbîrāyw</em>): the soundscape of approaching cavalry — the thunder of hoofs (<em>šaʿăṭat pārsôt</em>, the stamping/clattering of hooves), the rumbling of chariots (<em>hāmôn galgillāyw</em>, the roar of their wheels). The acoustic terror of Babylonian chariot-forces is described with intense attention to sound, matching the visual intensity of v2's flood image. <strong>Lōʾ-pānû ʾāḇôt ʾel-bānîm mĕrippayôn yādāyim</strong> (<em>Lōʾ-pānû ʾāḇôt ʾel-bānîm mĕrippayôn yādāyim</em>): \"fathers will not turn back for their children — their hands go limp\" — the <em>rippayôn yādāyim</em> (limpness/slackness of hands — Jer 6:24; Isa 13:7; Ezek 7:17) is the physical manifestation of complete demoralization: soldiers so overcome with fear they cannot even reach for their children.</p>",
    "4": "<p><strong>ʿAl-hayyôm haBBāʾ lĕšadōd ʾet-kol-Pĕlištîm lĕhaḵrît lĕṣōr ûlĕṣîdôn kol śārid ʿōzēr</strong> (<em>lĕhaḵrît lĕṣōr ûlĕṣîdôn kol śārid ʿōzēr</em>): Tyre and Sidon (Phoenicia) are included as Philistia's commercial and military allies — their remaining support (<em>kol śārid ʿōzēr</em>, every remaining helper) will be cut off. <strong>Kî-šōdēd YHWH ʾet-Pĕlištîm šĕʾērît ʾî Kaptôr</strong> (<em>šĕʾērît ʾî Kaptôr</em>): \"for YHWH is destroying the Philistines, the remnant of the coastlands of Caphtor.\" <em>Kaptôr</em> (Crete or the Aegean region) is the Philistines' place of origin, cited also in Amos 9:7 (\"Did I not bring up the Philistines from Caphtor?\"). YHWH's sovereignty over the Philistines extends back to their own origin-migration.</p>",
    "5": "<p><strong>Bāʾâ qorḥâ ʾel-ʿazzâ nidmĕtâ ʾašqĕlôn šĕʾērît ʿimqām</strong> (<em>Bāʾâ qorḥâ ʾel-ʿazzâ nidmĕtâ ʾašqĕlôn</em>): Gaza is shaved bald (<em>qorḥâ</em>, the mourning rite of head-shaving, Amos 8:10; Mic 1:16; Isa 15:2); Ashkelon is silenced/destroyed (<em>nidmĕtâ</em>, Niphal of <em>dāmam</em>). <strong>ʿAd-mātay titgōdĕdî</strong> (<em>ʿAd-mātay titgōdĕdî</em>): \"how long will you slash yourself?\" — <em>gādad</em> (to slash, cut) refers to the mourning practice of self-laceration forbidden to Israel (Lev 19:28; Deut 14:1) but practiced by neighboring peoples (cf. 1 Kings 18:28; Zech 13:6). The question implies the mourning is endless because the devastation is total.</p>",
    "6": "<p><strong>Hôy ḥereḇ laYHWH ʿad-ʾānâ lōʾ tišqôṭî</strong> (<em>Hôy ḥereḇ laYHWH ʿad-ʾānâ lōʾ tišqôṭî</em>): the sword-lament — a unique personification in the OAN collection. The prophet addresses YHWH's sword: \"O sword of YHWH, how long before you rest?\" <strong>Hēʾāsĕpî ʾel-taʿrēḵ hĕrāgĕʿî wĕdōmî</strong> (<em>Hēʾāsĕpî ʾel-taʿrēḵ hĕrāgĕʿî wĕdōmî</em>): \"Return to your sheath; be still and stop.\" The pathos of this plea — the prophet lamenting the extent of divine judgment — is comparable to the Confessions (4:10; 14:13; 20:7). The sword is felt as a burden even when its action is just.</p>",
    "7": "<p><strong>Êḵ tišqôṭî wĕYHWH ṣiwwāh-lāh ʾel-ʾašqĕlôn wĕʾel-ḥôp hayyām šāmmâ yĕʾādāh</strong> (<em>wĕYHWH ṣiwwāh-lāh ʾel-ʾašqĕlôn</em>): the rhetorical answer ends the oracle — \"How can it be still when YHWH has given it its charge? Against Ashkelon and the seacoast — there he has set it.\" The sword cannot rest because it is executing a divinely-ordered commission (<em>YHWH ṣiwwāh-lāh</em>, YHWH commanded it). The lament of v6 is answered not with false comfort but with honest acknowledgment: the judgment is real, authorized, and specific. This frank dialogue with the divine sword's necessity reflects Jeremiah's mature prophetic voice — he does not deny the horror of judgment but locates it within YHWH's sovereign purpose.</p>"
  },
  "48": {
    "1": "<p>The Moab oracle (chs 48) is the longest OAN in Jeremiah and one of the most extensively developed in all prophetic literature. It draws heavily from Isaiah 15-16 and Numbers 21. <strong>Lĕmôʾāḇ kōh ʾāmar YHWH ṣĕḇāʾôt ʾĕlōhê yiśrāʾēl hôy ʿal-Nĕḇô kî šuddādâ</strong> (<em>hôy ʿal-Nĕḇô kî šuddādâ</em>): the oracle opens with <em>hôy</em> (woe, funeral cry) over Nebo, a Moabite city on or near Mount Nebo (from which Moses viewed Canaan, Deut 34:1). <strong>Qiryātāyim hōḇîšâ nileḵĕdâ hammiśgāḇ hōḇîšâ ûḥāttâ</strong> (<em>hōḇîšâ wĕḥāttâ</em>): Kiriathaim (twin cities, a Reubenite then Moabite town, Num 32:37; Ezek 25:9) and the stronghold are shamed and shattered — three <em>hōḇîšâ</em> words in this verse and the next create a drumbeat of shame.</p>",
    "2": "<p><strong>ʾên ʿôd tehillat Môʾāḇ bĕḤešbôn ḥāšĕḇû ʿālêhā rāʿâ lĕkû wĕnaḵrîtennāh miggôy</strong> (<em>ḥāšĕḇû ʿālêhā rāʿâ lĕkû wĕnaḵrîtennāh miggôy</em>): \"in Heshbon they have plotted its ruin: Come, let us cut it off as a nation.\" The wordplay on <em>Ḥešbôn</em>/<em>ḥāšĕḇû</em> (Heshbon/they have devised) — the city's name echoes the verb for scheming — is a classic prophetic omen-name technique (cf. Jer 1:12: <em>šāqēd/šōqēd</em>). <strong>Gam-madmēn tiddōmmî ʾaḥărêḵ tēlēḵ ḥāreḇ</strong> (<em>Gam-madmēn tiddōmmî</em>): Madmen will also be silenced — the wordplay continues: <em>Madmēn/tiddōmmî</em> (Madmen/will be silenced; <em>dāmam</em>).</p>",
    "3": "<p><strong>Qôl ṣĕʿāqâ mîḤōrônāyim šōd ûšeḇer gādôl</strong> (<em>Qôl ṣĕʿāqâ mîḤōrônāyim šōd ûšeḇer gādôl</em>): Horonaim (\"two caverns,\" a Moabite town, Isa 15:5) — the cry of ruin (<em>šōd ûšeḇer gādôl</em>, devastation and great breaking) heard from there signals the cascade of destruction moving through the Moabite city network. The OAN moves town by town through Moab's geography — a literary technique that creates the effect of a reportage from a moving front line.</p>",
    "4": "<p><strong>Nišbĕrâ Môʾāḇ hišmîʿû zĕʿāqâ ṣĕʿirêhā</strong> (<em>Nišbĕrâ Môʾāḇ hišmîʿû zĕʿāqâ ṣĕʿirêhā</em>): \"Moab is shattered; her young ones raise a cry.\" <em>Nišbĕrâ</em> (Niphal perfect of <em>šāḇar</em>, to shatter) signals total structural collapse; <em>ṣĕʿirêhā</em> (her little ones) are either children literally weeping or the small towns of Moab crying out. The LXX reads \"even to Zoar\" which connects to v34, but the MT reading of \"young ones/little ones\" produces a poignant image of total vulnerability — even children bear the war's destruction.</p>",
    "5": "<p><strong>Kî maʿălēh-halûḥît bĕḇekî yaʿăleh-bô kî bĕmôrad ḥōrônāyim ṣārê-yĕlalelû šĕḇer</strong> (<em>Kî maʿălēh-halûḥît bĕḇekî yaʿăleh-bô</em>): the ascent of Luhith (also cited in Isa 15:5) and the road down to Horonaim are the two main routes of Moab — one going up, one going down — and on both the refugees flee in continuous weeping (<em>bĕḇekî tamrûrîm</em>, with bitter weeping) and cries of anguish (<em>ṣārê-yĕlalelû šĕḇer</em>). The geography of Moab's road system becomes the geography of its mourning.</p>",
    "6": "<p><strong>Nûsû mallĕṭû napšĕḵem ûḵĕʿarôʿēr bammidbar tihyû</strong> (<em>ûḵĕʿarôʿēr bammidbar tihyû</em>): \"Flee! Save yourselves! Be like a desert shrub (<em>ʿarôʿēr</em>) in the wilderness.\" The word <em>ʿarôʿēr</em> (juniper/tamarisk, a solitary shrub) is the same used in 17:6 for the man who trusts in human beings instead of YHWH: \"he is like a shrub in the desert and shall not see any good come.\" By calling Moab to become what the cursed man is, the oracle identifies Moab's condition as the direct consequence of misplaced trust (v7: \"because you trusted in your works\").</p>",
    "7": "<p><strong>Kî yaʿan biṭḥēḵ bĕmaʿăśayiḵ ûḇĕʾôṣĕrôtêḵ gam-ʾat tillaḵēdî</strong> (<em>Kî yaʿan biṭḥēḵ bĕmaʿăśayiḵ ûḇĕʾôṣĕrôtêḵ</em>): the theological root of Moab's judgment — trust (<em>bāṭaḥ</em>) in her own works (<em>maʿăśāyim</em>, both deeds and manufactured goods/idols) and in her storehouses (<em>ʾôṣĕrôt</em>, treasure-houses, reserves). This is the antithesis of the trust YHWH requires (cf. 17:7-8: blessed is the person who trusts in YHWH). <strong>Wĕyāṣāʾ Kĕmôš baggōlâ hûʾ wĕkōhănāyw wĕśārāyw yaḥdāw</strong> (<em>Wĕyāṣāʾ Kĕmôš baggōlâ</em>): Chemosh, Moab's national deity (Num 21:29; Judg 11:24; 1 Kings 11:7, 33) goes into exile along with his priests and officials. The defeat of a people's patron deity is the ultimate OAN statement: Chemosh cannot protect Moab because he himself is carried off as conquered territory. Cf. Isa 46:1-2 (Bel and Nebo borne away on beasts of burden).</p>",
    "8": "<p><strong>Wĕyāḇôʾ šōdēd ʾel-kol-ʿîr wĕʿîr lōʾ timmāleṭ wĕʾāḇad haʿēmeq wĕnišmad hammîšôr kaʾăšer dibber YHWH</strong> (<em>kaʾăšer dibber YHWH</em>): \"the destroyer will come to every city; not one city will escape... exactly as YHWH has decreed.\" The oracle's completion formula (<em>kaʾăšer dibber YHWH</em>) anchors the prediction's authority: what has happened/will happen fulfills the divine word. The completeness — every city (<em>kol-ʿîr wĕʿîr</em>), not one escaping (<em>lōʾ timmāleṭ</em>) — gives the valley and plateau no shelter.</p>",
    "9": "<p><strong>Tĕnû ṣîṣ lĕMôʾāḇ kî nāṣōʾ tēṣēʾ</strong> (<em>Tĕnû ṣîṣ lĕMôʾāḇ kî nāṣōʾ tēṣēʾ</em>): the command \"give wings to Moab so she may fly away\" is sardonic — Moab will need wings because flight is the only remaining option. <em>nāṣōʾ tēṣēʾ</em> (the doubled infinitive absolute: she will surely fly away) uses the doubled form to express certainty; the irony is that the only \"flight\" available is the hopeless flight of refugee flight, not the soaring of freedom. <strong>Wĕʿārêhā lĕšammâ tihyênâ mēʾên yôšēḇ bāhen</strong> (<em>lĕšammâ tihyênâ mēʾên yôšēḇ</em>): the desolation formula — cities becoming <em>šammâ</em> (desolation) without inhabitants — is the same formula applied to Jerusalem (4:7) and Egypt (46:19). No people is exempt from this consequence of covenant/divine-law violation.</p>",
    "10": "<p><strong>ʾĀrûr ʿōśeh mĕleʾḵet YHWH rĕmiyyâ wĕʾārûr mōnēaʿ ḥarbô middām</strong> (<em>ʾĀrûr ʿōśeh mĕleʾḵet YHWH rĕmiyyâ wĕʾārûr mōnēaʿ ḥarbô middām</em>): a striking verse — \"cursed is the one who carries out YHWH's work negligently, and cursed is the one who holds his sword back from bloodshed.\" The oracle uses the covenant-curse formula (<em>ʾārûr</em>, Deut 27-28) to bind the Babylonian executors of judgment to full implementation. <em>rĕmiyyâ</em> (slackness, negligence, deceit) — the <em>ʿōśeh mĕleʾḵet YHWH rĕmiyyâ</em> (one who does YHWH's work with slackness) is cursed along with the one who withholds violence. This verse creates significant theological tension — YHWH binding human soldiers to thoroughness in execution — but it reflects the consistent OAN theology that the conquering army is YHWH's instrument, not an autonomous agent.</p>",
    "11": "<p><strong>Šaqaṭ Môʾāḇ minĕʿûrāyw wĕšōqēṭ hûʾ ʿal-šĕmārāyw wĕlōʾ-hûraq mikkĕlî ʾel-kēlî ûḇaggōlâ lōʾ-hālāḵ</strong> (<em>wĕlōʾ-hûraq mikkĕlî ʾel-kēlî</em>): the wine-on-its-dregs metaphor is the most distinctive image in the Moab oracle. Moab is like undisturbed wine that has never been poured from vessel to vessel — unfiltered wine left on its sediment develops a corrupted, stale flavor. The refinement process of pouring wine from jar to jar (to separate it from the lees/dregs, <em>šĕmārîm</em>) is what creates clarity and quality. <strong>ʿAl-kēn ʿāmad ṭaʿmô bô wĕrêḥô lōʾ nāmār</strong> (<em>ʿāmad ṭaʿmô bô wĕrêḥô lōʾ nāmār</em>): \"his flavor has stayed in him and his aroma has not changed\" — the metaphor: Moab's undisturbed prosperity (no exile, no external pressure) has produced cultural/moral stagnation. Peace without discipline produces corruption rather than character. Cf. Ps 55:19 (\"those who have no changes dread not God\").</p>",
    "12": "<p><strong>Lāḵēn hinnēh yāmîm bāʾîm nĕʾum-YHWH wĕšillaḥtî-lô ṣōʿîm wĕṣĕrûhû ûkĕlêhû yāreqqû wĕnibĕlêhem yĕnappēṣû</strong> (<em>wĕšillaḥtî-lô ṣōʿîm wĕṣĕrûhû</em>): \"I will send wine-tilters (<em>ṣōʿîm</em>, those who tilt/pour) who will tip him over and empty his vessels and smash his jars.\" The YHWH-as-vintner sends agents to do what should have been done through natural historical process — the exile (being poured from vessel to vessel) that Moab escaped becomes a violent compulsory process. <em>wĕnibĕlêhem yĕnappēṣû</em> (and his containers — <em>nēḇel</em>, wine-jug — will be smashed): the smashed wine-jug image echoes Jeremiah's own sign-act with the pottery flask (<em>baqbûq</em>) in ch19 — the broken jar as irreversible judgment.</p>",
    "13": "<p><strong>Wĕḇôš Môʾāḇ miKKĕmôš kaʾăšer-bôšû bêt-yiśrāʾēl mibBêt ʾēl miḇṭaḥām</strong> (<em>kaʾăšer-bôšû bêt-yiśrāʾēl mibBêt ʾēl miḇṭaḥām</em>): the comparison to Israel's shame over Bethel is historically precise — the golden calves established by Jeroboam I at Bethel and Dan (1 Kings 12:28-29) were the defining apostasy of the northern kingdom. Israel trusted (<em>bāṭaḥ</em>) in Bethel's bulls; they were proved worthless. Moab trusted in Chemosh; Chemosh too will be proved worthless. The comparison democratizes the experience of idolatrous shame: Israel's history of false trust is the template for the nations' judgment.</p>",
    "14": "<p><strong>Êḵ tōmĕrû ʾănaḥnû gibbōrîm wĕʾanšê-ḥayil lammilḥāmâ</strong> (<em>ʾănaḥnû gibbōrîm wĕʾanšê-ḥayil lammilḥāmâ</em>): the rhetorical question challenges Moab's self-description as \"heroes, battle-hardened men\" (<em>gibbōrîm... ʾanšê-ḥayil</em>). The vocabulary of military prowess — <em>gibbôr</em> (mighty warrior), <em>ʾîš ḥayil</em> (man of valor) — is the language of Moab's own boasting. This sets up the inversion: the claim of might makes the collapse more devastating. <em>Êḵ</em> (How?) — the same funeral-lament interrogative used in the book of Lamentations (1:1; 2:1; 4:1) — frames the self-congratulatory claim as already past, a subject of lamentation.</p>",
    "15": "<p><strong>Šuddad Môʾāḇ wĕʿārêhā ʿālâ ûmibḥar baḥûrāyw yārĕdû laṭṭāḇaḥ</strong> (<em>wĕʿārêhā ʿālâ ûmibḥar baḥûrāyw yārĕdû laṭṭāḇaḥ</em>): the devastation is comprehensive — the cities are overrun and the choicest (<em>mibḥar</em>) young men go down to slaughter (<em>laṭṭāḇaḥ</em>, the slaughterhouse term; cf. Isa 53:7; Jer 11:19 — both uses of the slaughter-lamb). <strong>Nĕʾum-hammelek YHWH ṣĕḇāʾôt šĕmô</strong> (<em>Nĕʾum-hammelek YHWH ṣĕḇāʾôt šĕmô</em>): \"declares the King, the LORD of hosts is his name\" — the divine warrior title (<em>YHWH ṣĕḇāʾôt</em>) with <em>hammelek</em> (the King) combines to present YHWH as the sovereign who commands both the cosmic army and the judgment of nations. Cf. Mal 1:14 (\"I am a great King, says the LORD of hosts\").</p>",
    "16": "<p><strong>Qārôḇ ʾêd Môʾāḇ lāḇôʾ wĕrāʿātô māhĕrâ mĕʾōd</strong> (<em>Qārôḇ ʾêd Môʾāḇ lāḇôʾ wĕrāʿātô māhĕrâ mĕʾōd</em>): the catastrophe is described as imminent — \"Moab's disaster is close at hand and his ruin coming very quickly.\" <em>ʾêd</em> (disaster, doom, calamity) appears in the Wisdom literature (Prov 1:26-27; 6:15; 24:22) for sudden catastrophe; in Jer 18:17 YHWH shows the back not the face on the day of their <em>ʾêd</em>. The speed (<em>māhĕrâ mĕʾōd</em>) and proximity (<em>qārôḇ</em>) together convey the urgency of irreversibility — there is no more time for repentance.</p>",
    "17": "<p><strong>Nûdû lô kol-sĕḇîḇāyw wĕḵol-yōdĕʿê šĕmô ʾimrû ʾêḵ nišbar maṭṭēh-ʿōz maqqēl tipʾāret</strong> (<em>ʾêḵ nišbar maṭṭēh-ʿōz maqqēl tipʾāret</em>): the funeral lament formula — <em>ʾêḵ</em> (how!) + passive verb of destruction. The \"powerful scepter\" (<em>maṭṭēh-ʿōz</em>) and \"glorious staff\" (<em>maqqēl tipʾāret</em>) are regalia of royal power — Moab's imperial sovereignty is the scepter/staff that is broken. Cf. Ezek 19:10-14 (the lament over Judah's scepter/vine); Isa 9:4; 10:24 (breaking the rod of oppression). The lament is addressed to those who surround Moab and know its name — a call to communal mourning for what was, rather than what Moab became.</p>",
    "18": "<p><strong>Rĕdî miqqāḇôd wĕšĕḇî baṣṣāmāʾ yōšeḇet bat-Dîḇôn</strong> (<em>Rĕdî miqqāḇôd wĕšĕḇî baṣṣāmāʾ</em>): \"Come down from your glory and sit in thirst, O inhabitants of Dibon.\" <em>Kāḇôd</em> (glory, weight, honor) down to <em>ṣāmāʾ</em> (thirst, drought) — the polarity is absolute: from the height of national glory to the parched ground of refugee thirst. Dibon was Mesha's royal city (the Mesha Stele describes his building activities there, ~850 BCE). <strong>Kî šōdēd Môʾāḇ ʿālâ ḇāḵ šiḥat miḇṣārāyiḵ</strong> (<em>kî šōdēd Môʾāḇ ʿālâ ḇāḵ šiḥat miḇṣārāyiḵ</em>): the destroyer has come up against Dibon's fortresses (<em>miḇṣārîm</em>, fortified places) and ruined them.</p>",
    "19": "<p><strong>ʿimĕdî hadd-dereḵ ûṣappî yōšeḇet ʿarôʿēr šaʾălî nās ûmāleṭ ʾimrî mah-nîhyâ</strong> (<em>ʿimĕdî hadd-dereḵ ûṣappî... šaʾălî nās ûmāleṭ</em>): the command to Aroer (on the Arnon River, the southern boundary of Moab's territory, Deut 2:36; 3:12) to stand by the road and question the fleeing and escaping: \"What has happened?\" (<em>mah-nîhyâ</em>). The question is rhetorical — the questioner will receive a report of total collapse. The posting of a town at the crossroads to gather news from refugees mirrors the way ancient Near Eastern cities functioned as information nodes during military campaigns.</p>",
    "20": "<p><strong>Hōḇîš Môʾāḇ kî ḥattâ hêlîlî ûzʿāqî haggîdû ʾaḇ-ʾARNÔN kî šuddad Môʾāḇ</strong> (<em>hêlîlî ûzʿāqî haggîdû ʾaḇ-ʾARNÔN kî šuddad Môʾāḇ</em>): the lamentation intensifies — Moab is shamed, shattered; the command is to wail, cry, and announce it at the Arnon. <em>hêlîl</em> (wail, howl — the funeral cry used in Isa 13:6; Ezek 21:12; Amos 8:3; Joel 1:5) is the distinctive sound of prophetic judgment literature, the vocalization of <em>šammâ</em> (desolation). The announcement at the Arnon (Moab's northern boundary with Israel) signals the collapse is complete from border to border.</p>",
    "21": "<p><strong>Ûmišpāṭ bāʾ ʾel-ʾereṣ hammîšôr ʾel-Ḥôlôn wĕʾel-Yahṣâ wĕʿal-Môpāʿat</strong> (<em>Ûmišpāṭ bāʾ ʾel-ʾereṣ hammîšôr</em>): the long list of Moabite cities (vv21-24) to which judgment comes exemplifies the prophetic list-curse. Each city-name carries the rhetorical weight of a funeral toll. <em>Hammîšôr</em> (the Plateau/Tableland) is the high Transjordanian plateau east of the Dead Sea — the heartland of Moab's agriculture and settlement. Holon, Jahzah (site of Israel's battle with Sihon, Num 21:23), and Mephaath are named in the Reubenite city lists (Josh 13:17-21).</p>",
    "22": "<p><strong>Wĕʿal-Dîḇôn wĕʿal-Nĕḇô wĕʿal-Bêt-Diḇlātāyim</strong>: Dibon (Mesha's royal city), Nebo (where the inscription found in 1868 naming Moab was excavated near Mount Nebo), and Beth-diblathaim continue the city-by-city roll call of judgment. Each name is a place where real people lived, farmed, and prayed — the oracle's specificity prevents it from being abstracted into generic judgment rhetoric. This is the same technique Jeremiah uses for Jerusalem's own doom (30:4-7; 51:54).</p>",
    "23": "<p><strong>Wĕʿal-Qiryātāyim wĕʿal-Bêt-Gāmûl wĕʿal-Bêt-Mĕʿôn</strong>: Kiriathaim (mentioned in v1), Beth-gamul (unidentified but Moabite), and Beth-meon (also called Baal-meon, Num 32:38; Ezek 25:9 — a city whose very name embeds the Baal cult). The Baal-meon connection anticipates v35's oracle against Moabite high-place religion.</p>",
    "24": "<p><strong>Wĕʿal-Qĕriyyôt wĕʿal-Boṣrâ wĕʿal kol-ʿārê ʾereṣ-Môʾāḇ hārĕḥōqôt wĕhaqqĕrōḇôt</strong> (<em>hārĕḥōqôt wĕhaqqĕrōḇôt</em>): the list concludes with Kerioth and Bozrah (the latter appears also in the Edom oracle, 49:13, 22; Amos 1:12) and the comprehensive formula \"all the cities of the land of Moab, far and near.\" <em>hārĕḥōqôt wĕhaqqĕrōḇôt</em> (the distant and the near) — geographic totality, the formula of complete coverage (cf. Deut 13:7; 29:22; 1 Kings 8:46).</p>",
    "25": "<p><strong>Nîgdĕʿâ qeren Môʾāḇ ûzĕrōʿô nišbārâ nĕʾum-YHWH</strong> (<em>Nîgdĕʿâ qeren Môʾāḇ ûzĕrōʿô nišbārâ</em>): the oracle-within-a-list: <em>qeren</em> (horn, symbol of power and pride — Ps 75:5-10; Lam 2:3; Amos 6:13) and <em>zĕrôaʿ</em> (arm, symbol of military strength) are hewn off and broken. The two images together cover both the external display of power (horn as crown-symbol) and the instrument of power (arm). YHWH as the one who breaks the nations' power is the theological thread running through the entire OAN collection.</p>",
    "26": "<p><strong>Hašḵîrûhû kî ʿal-YHWH higdîl wĕsāpaq Môʾāḇ bĕqîʾô wĕhāyâ lĭśĕḥōq gam-hûʾ</strong> (<em>kî ʿal-YHWH higdîl</em>): the sin specified — Moab \"exalted himself against YHWH\" (<em>higdîl ʿal-YHWH</em>). The Hiphil of <em>gādal</em> (to make oneself great/lifted above) applied to <em>ʿal-YHWH</em> (against/above YHWH) is the defining sin of hubris — positioning oneself above or in opposition to YHWH's sovereignty. <strong>Wĕsāpaq Môʾāḇ bĕqîʾô wĕhāyâ lĭśĕḥōq gam-hûʾ</strong> (<em>wĕsāpaq Môʾāḇ bĕqîʾô</em>): \"Moab will wallow in his own vomit\" — the drunkenness image (<em>hašḵîrûhû</em>, make him drunk) leads to the degradation of vomiting in his own filth, becoming an object of ridicule (<em>śĕḥōq</em>). Cf. Hab 2:16: shame covers glory when the cup of YHWH's wrath is drunk.</p>",
    "27": "<p><strong>Wĕʾim-lōʾ lĭśĕḥōq hāyâ lĕḵā yiśrāʾēl ʾim-biggannāḇîm nimṣāʾ</strong> (<em>Wĕʾim-lōʾ lĭśĕḥōq hāyâ lĕḵā yiśrāʾēl ʾim-biggannāḇîm nimṣāʾ</em>): the oracle turns the mockery back on Moab — \"Was not Israel a laughingstock to you? Was he found among thieves?\" The question carries the logic of judgment's reversal: Moab mocked Israel in her humiliation; now Moab will be mocked. <strong>Kî-midday dibbārĕḵā bô tinnôdēd</strong> (<em>kî-midday dibbārĕḵā bô tinnôdēd</strong>): \"For whenever you spoke of him you wagged your head (tinnôdēd, the head-shaking gesture of contempt, Ps 22:7; Lam 2:15)\" — Moab's contemptuous commentary on Israel's fall is what makes Moab's own fall a matter of divine justice-in-kind.</p>",
    "28": "<p><strong>ʿIzĕḇû ʿārîm wĕšiḵnû bassela yōšĕḇê Môʾāḇ wĕhiyyû kĕyônâ tĕqannēn bĕʿeḇrê pî-paḥat</strong> (<em>wĕhiyyû kĕyônâ tĕqannēn bĕʿeḇrê pî-paḥat</em>): \"Be like the dove that builds its nest deep in the walls of a ravine.\" The dove (<em>yônâ</em>) nesting deep in the cliff-walls (<em>bĕʿeḇrê pî-paḥat</em>, on the far side of the mouth of the pit/ravine) is an image of the most hidden, inaccessible nesting — Moab must seek the deepest hiding possible, because the cities offer no protection. Cf. Song 2:14 (\"my dove in the clefts of the rock\") — the same image of cliff-refuge, there used lovingly; here it is counsel of desperate concealment.</p>",
    "29": "<p><strong>Šāmaʿnû gĕʾôn-Môʾāḇ gēʾeh mĕʾōd gabbĕhûtô wĕgaʾăwātô wĕgĕʾônô wĕrûm libbô</strong> (<em>Šāmaʿnû gĕʾôn-Môʾāḇ gēʾeh mĕʾōd</em>): five words for Moab's pride in a single verse — <em>gĕʾôn</em> (majesty/pride), <em>gēʾeh</em> (haughty), <em>gabbĕhût</em> (loftiness), <em>gaʾăwâ</em> (arrogance), <em>rûm lēḇ</em> (exaltation of heart). The concentration creates a portrait of a nation whose self-assessment was its central feature — and its fatal flaw. Cf. Isa 16:6 (the parallel passage): \"We have heard of the pride of Moab — how proud he is! — of his arrogance, his pride, and his insolence.\" Moab's pride is the standing OT example of national hubris against YHWH (cf. also Ezek 25:8-11).</p>",
    "30": "<p><strong>ʾĂnî yādaʿtî nĕʾum-YHWH ʿebrātô wĕlōʾ-ḵēn baddāyw lōʾ-ḵēn ʿāśû</strong> (<em>ʾĂnî yādaʿtî nĕʾum-YHWH ʿebrātô</em>): \"I know his arrogance, declares YHWH — but it comes to nothing; his empty boasts accomplish nothing.\" YHWH's declaration of knowledge (<em>yādaʿtî</em>, I know) is the divine omniscient assessment. <em>ʿebrâ</em> (arrogance, overflow — Prov 11:4; 21:24) is what YHWH knows; the double <em>lōʾ-ḵēn</em> (\"not so, not so\") is a dismissal: Moab's bluster is assessed, found hollow, and dismissed. YHWH's calm knowledge of Moab's pride contrasts with the dramatic military collapse described elsewhere in the chapter.</p>",
    "31": "<p><strong>Lāḵēn ʿal-Môʾāḇ ʾeylelāh wĕlĕḵol-Môʾāḇ ʾizʿāq lĕʾanšê Qîr-ḥereś ʾehgeh</strong> (<em>Lāḵēn ʿal-Môʾāḇ ʾeylelāh</em>): the divine lament — YHWH himself wails (<em>ʾeylelāh</em>, Qal imperfect of <em>yālal</em>, to wail) over Moab. This is theologically remarkable: the God who pronounces judgment over Moab also mourns over it. Cf. Jer 48:31 paralleling Isa 16:7 and the divine weeping in Isa 16:9-11. The same tension appears in Lam 3 (YHWH is both the agent of destruction and the one who does not abandon). The divine lament is not contradiction but the full expression of YHWH's character: judgment and compassion coexist.</p>",
    "32": "<p><strong>ʾEt-bĕḵî yĕʿaZĒR ʾeḇkeh-lāḵ gepen Śiḇmâ nĕṭîšōtayiḵ ʿāḇrû yam ʿad-yam yĕʿaZĒR higgîʿû</strong> (<em>gepen Śiḇmâ nĕṭîšōtayiḵ ʿāḇrû yam</em>): the lament over Sibmah's vines — the famous vineyards that spread their tendrils across the sea (the Dead Sea) to Jazer — is a regional elegy for agricultural abundance destroyed. <strong>ʿal-qayiṣēḵ wĕʿal-bĕṣîrĕḵā šōdēd nāpāl</strong> (<em>šōdēd nāpāl</em>): the destroyer has fallen on the summer fruit and vintage — harvest imagery for the destruction of Moab's agricultural identity. Cf. Isa 16:8-10 (the lament over Sibmah's vines in the parallel OAN).</p>",
    "33": "<p><strong>Wĕneʾespâ śimḥâ wāgîl mikkarmēl ûmēʾereṣ Môʾāḇ ûyayim miyyĕqāḇîm hibbattî yôdēd lōʾ-yôdēd lōʾ hēdād yēdād</strong> (<em>yayim miyyĕqāḇîm hibbattî yôdēd lōʾ-yôdēd</em>): joy and gladness stripped from the fertile fields. <em>Yôdēd</em> (the harvest shout, the treaders' cry) — \"the only shout is not a harvest shout.\" The harvest treading song (<em>hēdād</em>, shouting) is silenced; what replaces it is the silence of <em>lōʾ hēdād</em> (no shout). The agricultural calendar of joy — harvest festivals, communal celebration — is extinguished. Cf. Joel 1:11-12 (similar lament over agricultural devastation). Joy and gladness (<em>śimḥâ wāgîl</em>) are YHWH's gifts that can be withdrawn.</p>",
    "34": "<p><strong>Mizzĕʿaqat Ḥešbôn ʿad-ʾĔlāʿēlēh ʿad-Yahaz nātĕnû qôlām miṣṣōʿar ʿad-Ḥōrônāyim ʿeglat šĕlîšiyyâ kî gam-mê Nimrîm lĭmšammôt yihyû</strong> (<em>kî gam-mê Nimrîm lĭmšammôt yihyû</em>): the sweep of the cry from Heshbon to Elealeh (NE of Heshbon), to Jahaz, Zoar (near the S end of the Dead Sea), to Horonaim — this geographic traversal names the major northsouth axis of Moab. <em>ʿeglat šĕlîšiyyâ</em> (\"like a three-year-old heifer's bellow\") — the bellowing of a fully grown, unsacrificed heifer is the image for the loudness of the cry. Even the waters of Nimrim (probably the Wadi Nimrin, north of the Dead Sea) will be dried up — the fundamental resources of water and agriculture fail together.</p>",
    "35": "<p><strong>Wĕhišbattî lĕMôʾāḇ nĕʾum-YHWH maʿăleh bāmâ wĕmaqṭîr lēʾlōhāyw</strong> (<em>Wĕhišbattî lĕMôʾāḇ... maʿăleh bāmâ wĕmaqṭîr lēʾlōhāyw</em>): YHWH will put an end in Moab to anyone who brings offerings to the high places (<em>bāmôt</em>) and burns incense to his gods (<em>lēʾlōhāyw</em>). The Moabite high places and their cult are the specific target of divine abolition — the same judgment language used for Israel's syncretistic worship (1 Kings 11:7; 2 Kings 23:13-14). Chemosh was worshiped at high places throughout Moab; their elimination marks the end of Moab's national-religious identity.</p>",
    "36": "<p><strong>Lāḵēn libbî lĕMôʾāḇ kaḥălîlîm yĕhemeh ûlibbî ʾel-ʾanšê Qîr-ḥereś kaḥălîlîm yĕhemeh</strong> (<em>libbî lĕMôʾāḇ kaḥălîlîm yĕhemeh</em>): \"my heart wails for Moab like flutes\" — the divine heart (<em>lēḇ</em>) wailing like funeral flutes (<em>ḥălîlîm</em>, pipe-flutes used at funerals; Matt 9:23 refers to flute-players at death) is the OT expression of divine compassion within judgment. The double repetition (\"my heart wails for Moab like flutes... my heart wails like flutes for the men of Kir-hareseth\") creates a liturgical lament. <strong>ʿal-kēn yitrat ʿāśâ ʾāḇādû</strong> (<em>yitrat ʿāśâ ʾāḇādû</em>): \"for the riches they gathered have perished\" — the accumulated wealth that Moab trusted (v7: <em>biṭḥēḵ bĕmaʿăśayiḵ ûḇĕʾôṣĕrôtêḵ</em>) is gone.</p>",
    "37": "<p><strong>Kî ḵol-rōʾš qorḥâ wĕḵol-zāqān gĕrûʿâ ʿal-kol-yādāyim gĕdûdōt ûʿal-mŏtnāyim śāq</strong> (<em>kî ḵol-rōʾš qorḥâ wĕḵol-zāqān gĕrûʿâ</em>): the comprehensive mourning rites — every head shaved (<em>qorḥâ</em>), every beard cut (<em>gĕrûʿâ</em>), gashes on every hand (<em>gĕdûdōt</em>), sackcloth around every waist — enumerate all four of the standard ancient Near Eastern mourning gestures (cf. Isa 15:2-3; Ezek 27:30-31; Amos 8:10). The universal coverage (\"every\" repeated four times) signals that Moab's entire population is in mourning — no exceptions, no exemptions.</p>",
    "38": "<p><strong>ʿAl-kol-gaggôt Môʾāḇ ûbirḥōḇōtêhā kulloh misped kî šāḇartî ʾet-Môʾāḇ kikĕlî ʾên-ḥēpeṣ bô nĕʾum-YHWH</strong> (<em>šāḇartî ʾet-Môʾāḇ kikĕlî ʾên-ḥēpeṣ bô</em>): YHWH's first-person claim: \"I have shattered Moab like a pot no one wants\" — <em>kĕlî ʾên-ḥēpeṣ</em> (vessel in which there is no pleasure/desire) is a broken, worthless piece of pottery. The same image of the worthless broken vessel appears in Hos 8:8 (\"Israel is swallowed up; among the nations he is like a vessel no one wants\") and Ps 31:12. The pottery imagery throughout Jeremiah (1:10; 18-19; 32; 45) reaches its final OAN expression here: Moab, like the nations, like Jerusalem, is clay in the potter YHWH's hands — broken when he chooses.</p>",
    "39": "<p><strong>Êḵ ḥattâ hêlîlû êḵ-hipnâ ʿōrep Môʾāḇ bôš wĕhāyâ Môʾāḇ lĭśĕḥōq ûlĕmaḥittâ lĕḵol-sĕḇîḇāyw</strong> (<em>êḵ-hipnâ ʿōrep Môʾāḇ bôš</em>): the lament (<em>êḵ ḥattâ hêlîlû</em>, \"how it is shattered — wail!\") and the specific humiliation — Moab turned its back (<em>ʿōrep</em>) in shame. The same vocabulary used for Israel's apostasy (2:27; 32:33: \"they turned their back to me, not their face\") applies to Moab's military flight. The turning of the back in battle is both physical retreat and symbolic rejection — shame embodied in posture. <em>lĭśĕḥōq ûlĕmaḥittâ</em> (a laughingstock and a terror) — the reversal of Moab's own contemptuous mockery of Israel (v27).</p>",
    "40": "<p><strong>Kî ḵōh ʾāmar YHWH hinnēh kaṇṇešer yidʾeh ûpāraś kĕnāpāyw ʾel-Môʾāḇ</strong> (<em>hinnēh kaṇṇešer yidʾeh ûpāraś kĕnāpāyw ʾel-Môʾāḇ</em>): the eagle simile for the conqueror — YHWH (or Nebuchadnezzar as YHWH's agent) swoops like a <em>nešer</em> (eagle/vulture, the largest and most powerful raptor of the ANE) spreading wings over Moab. The same image appears for Babylon's invasion of Judah (Ezek 17:3: \"a great eagle came to Lebanon\"; Hab 1:8: \"their horses fly like eagles\") and for Edom (Jer 49:22; Lam 4:19). The eagle/vulture embodies the irreversible, airborne speed of military conquest.</p>",
    "41": "<p><strong>Nilkĕdâ haqqĕriyyôt wĕhammĕṣādôt niltāḥû wĕhāyâ lēḇ gibborê Môʾāḇ bayyôm hahûʾ kĕlēḇ ʾiššâ mĕṣērâ</strong> (<em>wĕhāyâ lēḇ gibborê Môʾāḇ bayyôm hahûʾ kĕlēḇ ʾiššâ mĕṣērâ</em>): Kerioth and the fortresses taken; the hearts of Moab's warriors are like the heart of a woman in labor (<em>mĕṣērâ</em>, the one in labor-pain). The labor-pain simile for terror and helplessness recurs throughout the OAN (46:24; 49:22-24; 50:43) and Israel's own judgment (4:31; 13:21; 22:23; 30:6) — it crosses gender boundaries to describe absolute vulnerability and loss of control.</p>",
    "42": "<p><strong>Wĕniśmad Môʾāḇ mēʿam kî ʿal-YHWH higdîl</strong> (<em>kî ʿal-YHWH higdîl</em>): the sin summarized — \"Moab will be destroyed as a nation because he exalted himself against YHWH.\" The causal <em>kî ʿal-YHWH higdîl</em> (because he magnified himself against YHWH) is the oracle's theological thesis. This is the same sin identified in Babylon's judgment (50:24, 29, 31-32), in the king of Babylon's taunt (Isa 14:13-14), and in Nebuchadnezzar's narrative (Dan 4:30). National hubris against YHWH's sovereignty is the universal grounds for judgment in the prophetic literature.</p>",
    "43": "<p><strong>Paḥad wāpaḥat wāpāḥ ʿālêḵā yôšēḇ Môʾāḇ nĕʾum-YHWH</strong> (<em>Paḥad wāpaḥat wāpāḥ ʿālêḵā yôšēḇ Môʾāḇ</em>): the alliterative triple of terror — <em>paḥad</em> (terror, dread), <em>paḥat</em> (pit), and <em>pāḥ</em> (trap/snare) — three p/ph sounds creating the acoustic sensation of inescapable disaster. Isa 24:17 uses the identical formula (<em>paḥad wāpaḥat wāpāḥ</em>) for the universal judgment of the earth in the apocalyptic oracle. Jeremiah's use here intensifies the scope: what Isaiah applied to the whole earth, Jeremiah applies to Moab as a national representative of the principle.</p>",
    "44": "<p><strong>Hannās mippĕnê happāḥad yippōl ʾel-happāḥat wĕhaʿōleh min-happāḥat yillāḵēd bappāḥ kî ʾāḇîʾ ʾēlêhā ʾel-Môʾāḇ šĕnat pĕquddātām nĕʾum-YHWH</strong> (<em>Hannās mippĕnê happāḥad yippōl ʾel-happāḥat</em>): the three-word sequence from v43 becomes a three-stage scenario — the one who flees terror (<em>pāḥad</em>) falls into the pit (<em>paḥat</em>); the one who climbs out of the pit is caught in the trap (<em>pāḥ</em>). No escape route exists: flight leads to the pit, climbing out leads to the snare. This is the logic of inescapable divine judgment (cf. Amos 5:19: \"as if a man fled from a lion and a bear met him, or went into the house and a serpent bit him\"). <em>šĕnat pĕquddātām</em> (the year of their reckoning) — YHWH's appointed time of visitation, the same phrase used for Egypt's judgment (46:21).</p>",
    "45": "<p><strong>Bĕṣēl Ḥešbôn ʿāmĕdû mēḵōaḥ nāsîm kî-ʾēš yāṣāʾ mēḤešbôn wĕlehāḇâ mibbên Sîḥôn wattōʾḵal peʾat Môʾāḇ ûqodqod bĕnê-šāʾôn</strong> (<em>kî-ʾēš yāṣāʾ mēḤešbôn wĕlehāḇâ mibbên Sîḥôn</em>): an ancient poem about the Amorite king Sihon from Numbers 21:27-29 is cited — fire from Heshbon and flame from Sihon's midst devouring Moab. The citation of the old war-poem integrates the ancient tradition of Moab's vulnerability: the prophetic judgment is not new but the culmination of a long history of conflict. Sihon (<em>bên Sîḥôn</em>, within/from Sihon) was the Amorite king who defeated Moab before being himself defeated by Israel (Num 21:21-30). History's wheel turns through YHWH's sovereign direction.</p>",
    "46": "<p><strong>Ôy-lĕḵā Môʾāḇ ʾāḇad ʿam Kĕmôš kî luqqĕḥû bānêḵā baššĕḇî ûḇĕnōtêḵā baššiḇyâ</strong> (<em>ʾāḇad ʿam Kĕmôš</em>): \"the people of Chemosh are destroyed\" — the identification of Moab's national identity with Chemosh (<em>ʿam Kĕmôš</em>, people of Chemosh) echoes Numbers 21:29: \"Woe to you, Moab! You are ruined, O people of Chemosh.\" The oracle cites the ancient lament verbatim, completing the literary inclusio: what ancient poets saw in Moab's defeat by Sihon, Jeremiah now announces as YHWH's final judgment. <em>kî luqqĕḥû bānêḵā baššĕḇî ûḇĕnōtêḵā baššiḇyâ</em>: sons captured, daughters led captive — the social destruction of the family, the dismantling of future generations.</p>",
    "47": "<p><strong>Wĕšaḇtî šĕḇût-Môʾāḇ bĕʾaḥărît hayyāmîm nĕʾum-YHWH ʿad-hēnnâ mišpaṭ Môʾāḇ</strong> (<em>Wĕšaḇtî šĕḇût-Môʾāḇ bĕʾaḥărît hayyāmîm</em>): the chapter ends with an eschatological restoration footnote — \"Yet in the latter days I will restore the fortunes of Moab, declares YHWH.\" <em>šāḇ šĕḇût</em> (restore the fortunes) is the restoration formula used for Israel (30:3; 31:23; 32:44; 33:7, 11, 26) and here extended to Moab, Ammon (49:6), and Egypt (46:26). The inclusion of Moab's future restoration within the judgment oracle is consistent with YHWH's universal redemptive horizon — judgment is not the last word even for Moab. Paul's universalism in Romans 11:32 (\"God has consigned all to disobedience so that he may have mercy on all\") resonates with this trajectory: the same divine sovereignty that judges is the sovereignty that restores. <em>ʿad-hēnnâ mišpaṭ Môʾāḇ</em>: \"This is the end of the judgment of Moab\" — a formal closure formula marking the oracle's completion.</p>"
  }
}

def main():
    existing = load_comm("original", "jeremiah")
    merge_comm(existing, JEREMIAH)
    save_comm("original", "jeremiah", existing)
    total = sum(len(v) for v in existing.values())
    print(f"Jeremiah mkt-original: {len(existing)} chapters, {total} verses total.")

if __name__ == "__main__":
    main()
